class SecureCredentialManager(config: AwsServiceConfig) extends CredentialManager {

  override def getCredentialsProvider: AwsCredentialsProvider = {
    config.credentialSource match {
      case DefaultChain =>
        DefaultCredentialsProvider.create()

      case EnvironmentVariables =>
        resolveFromEnvironment()

      case SecretsManagerSource(secretName) =>
        resolveFromSecretsManager(secretName)

      case ProfileSource(profileName) =>
        software.amazon.awssdk.auth.credentials.ProfileCredentialsProvider
          .builder()
          .profileName(profileName)
          .build()
    }
  }

  private def resolveFromEnvironment(): AwsCredentialsProvider = {
    val accessKey = sys.env.getOrElse("AWS_ACCESS_KEY_ID",
      throw new IllegalStateException("AWS_ACCESS_KEY_ID environment variable is not set"))
    val secretKey = sys.env.getOrElse("AWS_SECRET_ACCESS_KEY",
      throw new IllegalStateException("AWS_SECRET_ACCESS_KEY environment variable is not set"))

    StaticCredentialsProvider.create(AwsBasicCredentials.create(accessKey, secretKey))
  }

  private def resolveFromSecretsManager(secretName: String): AwsCredentialsProvider = {
    val stsClient = SecretsManagerClient.builder()
      .region(config.region)
      .credentialsProvider(DefaultCredentialsProvider.create())
      .build()

    try {
      val request = GetSecretValueRequest.builder()
        .secretId(secretName)
        .build()

      val response = stsClient.getSecretValue(request)
      val secretString = response.secretString()

      val parsed = parseSecretJson(secretString)
      val accessKey = parsed.getOrElse("accessKeyId",
        throw new IllegalStateException("accessKeyId not found in secret"))
      val secretKey = parsed.getOrElse("secretAccessKey",
        throw new IllegalStateException("secretAccessKey not found in secret"))

      StaticCredentialsProvider.create(AwsBasicCredentials.create(accessKey, secretKey))
    } finally {
      stsClient.close()
    }
  }

  private def parseSecretJson(json: String): Map[String, String] = {
    val cleaned = json.trim.stripPrefix("{").stripSuffix("}")
    cleaned.split(",").map { pair =>
      val parts = pair.split(":", 2)
      val key = parts(0).trim.stripPrefix("\"").stripSuffix("\"")
      val value = parts(1).trim.stripPrefix("\"").stripSuffix("\"")
      key -> value
    }.toMap
  }
}

