      case Success(identity) =>
        println(s"[AwsServiceManager] Authenticated as account: ${identity.account}, ARN: ${identity.arn}")
        Success(())
      case Failure(ex) =>
        println(s"[AwsServiceManager] Credential verification failed: ${ex.getMessage}")
        Failure(ex)
    }
  }

  def shutdown(): Unit = {
    Try(s3.close())
    Try(sts.close())
    println("[AwsServiceManager] All clients shut down")
  }
}

